use std::time::{SystemTime, UNIX_EPOCH};
use std::error::Error;
use std::fmt;

#[derive(Debug, Clone)]
struct Document {
    content: String,
    timestamp: u64,
    version: u32,
}

enum InsertionMode {
    Push,
    Insert(usize),
}

#[derive(Debug)]
struct DuplicateTimestampError;

impl fmt::Display for DuplicateTimestampError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Document with duplicate timestamp detected")
    }
}

impl Error for DuplicateTimestampError {}

fn add_document_version(
    history: &mut Vec<Document>,
    content: String,
    mode: InsertionMode,
    custom_timestamp: Option<u64>,
) -> Result<(), Box<dyn Error>> {
    let timestamp = match custom_timestamp {
        Some(ts) => ts,
        None => SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("Time went backwards")
            .as_secs(),
    };

    // Check for duplicate timestamp
    if history.iter().any(|doc| doc.timestamp == timestamp) {
        return Err(Box::new(DuplicateTimestampError));
    }

    let version = history.len() as u32 + 1;
    let new_doc = Document {
        content,
        timestamp,
        version,
    };

    match mode {
        InsertionMode::Push => history.push(new_doc),
        InsertionMode::Insert(index) => {
            if index <= history.len() {
                history.insert(index, new_doc);
            } else {
                return Err("Index out of bounds".into());
            }
        }
    }

    Ok(())
}

