class SocialMediaTagManager {
private:
    std::set<std::string> userTags;

public:
    // Add a new tag using insert operation
    bool addTag(const std::string& tag) {
        auto result = userTags.insert(tag);
        return result.second; // Returns true if insertion took place
    }

    // Remove a tag using erase operation
    bool removeTag(const std::string& tag) {
        auto count = userTags.erase(tag);
        return count > 0; // Returns true if element was removed
    }

    // Check if a tag exists
    bool hasTag(const std::string& tag) const {
        return userTags.find(tag) != userTags.end();
    }

    // Get all tags (sorted order due to std::set)
    std::vector<std::string> getAllTags() const {
        return std::vector<std::string>(userTags.begin(), userTags.end());
    }

    // Get count of tags
    size_t getTagCount() const {
        return userTags.size();
    }

    // Evaluate scalability for large sets
    void evaluateScalability(int numOperations) {
        std::cout << "Evaluating scalability for " << numOperations << " operations using std::set...\n";

        // Generate test tags
        std::vector<std::string> testTags;
        for (int i = 0; i < numOperations; ++i) {
            testTags.push_back("event_tag_" + std::to_string(i));
        }

        // Measure insertion time using insert()
        auto startInsert = std::chrono::high_resolution_clock::now();
        for (const auto& tag : testTags) {
            userTags.insert(tag);
        }
        auto endInsert = std::chrono::high_resolution_clock::now();
        auto insertDuration = std::chrono::duration_cast<std::chrono::milliseconds>(endInsert - startInsert);

        // Measure removal time using erase()
        auto startErase = std::chrono::high_resolution_clock::now();
        for (const auto& tag : testTags) {
            userTags.erase(tag);
        }
        auto endErase = std::chrono::high_resolution_clock::now();
        auto eraseDuration = std::chrono::duration_cast<std::chrono::milliseconds>(endErase - startErase);

        std::cout << "Insert operations for " << numOperations << " items took: " 
                  << insertDuration.count() << " ms\n";
        std::cout << "Average time per insert: " 
                  << static_cast<double>(insertDuration.count()) / numOperations << " ms\n";

        std::cout << "Erase operations for " << numOperations << " items took: " 
                  << eraseDuration.count() << " ms\n";
        std::cout << "Average time per erase: " 
                  << static_cast<double>(eraseDuration.count()) / numOperations << " ms\n";

        std::cout << "Time complexity: O(log n) for both insert and erase operations\n";
    }
};

