from collections import OrderedDict

def lru_cache(capacity):
    cache = OrderedDict()

    def get(key):
        if key not in cache:
            return -1

        # Mark as most recently used
        cache.move_to_end(key)
        return cache[key]

    def put(key, value):
        # Update existing key
        if key in cache:
            cache[key] = value
            cache.move_to_end(key)
        else:
            # Remove least recently used item if at capacity
            if len(cache) >= capacity:
                cache.popitem(last=False)
            cache[key] = value

    return get, put
