public class NonConsecutiveMaxSum {
    public static int findMaxSum(int[] arr) {
        if (arr == null || arr.length == 0) return 0;
        if (arr.length == 1) return Math.max(0, arr[0]);

        HashMap<Integer, Integer> cache = new HashMap<>();
        cache.put(-1, 0);
        cache.put(0, Math.max(0, arr[0]));

        for (int i = 1; i < arr.length; i++) {
            // Option 1: Skip current element and take previous max
            int skipCurrent = cache.get(i - 1);

            // Option 2: Take current element and max sum from elements before the previous
            int takeCurrent = arr[i] + cache.get(i - 2);

            // Store the maximum of the two options
            int maxSum = Math.max(skipCurrent, takeCurrent);
            cache.put(i, maxSum);

            // Remove older entries we no longer need to optimize space
            // We only need the last two entries for future calculations
            if (i > 2) {
                cache.remove(i - 3);
            }
        }

        return cache.get(arr.length - 1);
    }
}

