    public void follow(String follower, String followed, long timestamp) {
        // Update follower's following list
        if (!following.containsKey(follower)) {
            following.put(follower, new HashSet<>());
        }
        Set<String> followingSet = following.get(follower);
        followingSet.add(followed);
        following.put(follower, followingSet);

        // Update followed's followers list
