        // Record the follow event
        followHistory.add(new FollowEvent(follower, followed, timestamp));
    }

    public String getLatestCommonFollower(String user1, String user2) {
        if (!followers.containsKey(user1) || !followers.containsKey(user2)) {
            return null;
        }

        Set<String> user1Followers = followers.get(user1);
        Set<String> user2Followers = followers.get(user2);

        // Find common followers
        Set<String> commonFollowers = new HashSet<>();
        for (String follower : user1Followers) {
            if (user2Followers.contains(follower)) {
                commonFollowers.add(follower);
            }
        }

        if (commonFollowers.isEmpty()) {
            return null;
        }

        // Find the latest common follower based on follow history
        String latestCommonFollower = null;
        long latestTimestamp = -1;

        for (int i = followHistory.size() - 1; i >= 0; i--) {
            FollowEvent event = followHistory.get(i);
            if (commonFollowers.contains(event.follower) && 
                (event.followed.equals(user1) || event.followed.equals(user2))) {
                latestCommonFollower = event.follower;
                break;
            }
        }

        return latestCommonFollower;
    }

    public List<String> suggestFriends(String user, int limit) {
        if (!following.containsKey(user)) {
            return new ArrayList<>();
        }

        Map<String, Integer> mutualConnectionCount = new HashMap<>();
        Set<String> userFollowing = following.get(user);

        // For each person the user follows
        for (String connection : userFollowing) {
            // Get who they follow
            if (following.containsKey(connection)) {
                Set<String> connectionFollowing = following.get(connection);
                for (String potentialFriend : connectionFollowing) {
                    // Don't suggest the user or people the user already follows
                    if (!potentialFriend.equals(user) && !userFollowing.contains(potentialFriend)) {
                        if (!mutualConnectionCount.containsKey(potentialFriend)) {
                            mutualConnectionCount.put(potentialFriend, 0);
                        }
                        int count = mutualConnectionCount.get(potentialFriend);
                        mutualConnectionCount.put(potentialFriend, count + 1);
                    }
                }
            }
        }

        // Sort by mutual connection count
        List<Map.Entry<String, Integer>> sortedSuggestions = new ArrayList<>(mutualConnectionCount.entrySet());
        sortedSuggestions.sort((a, b) -> b.getValue().compareTo(a.getValue()));

        List<String> suggestions = new ArrayList<>();
        for (int i = 0; i < Math.min(limit, sortedSuggestions.size()); i++) {
            suggestions.add(sortedSuggestions.get(i).getKey());
        }

        return suggestions;
    }

