import java.util.TreeMap;

public class LibraryInventory {
    private TreeMap<String, Book> inventory;

    public LibraryInventory() {
        inventory = new TreeMap<>();
    }

    /**
     * Manages the library book inventory using TreeMap operations
     * @param operation The operation to perform ("put" or "remove")
     * @param isbn The unique ISBN of the book
     * @param book The book object (only needed for put operation)
     * @return true if operation was successful, false otherwise
     */
    public boolean manageInventory(String operation, String isbn, Book book) {
        if (isbn == null || isbn.isEmpty()) {
            return false;
        }

        switch(operation) {
            case "put":
                if (book != null) {
                    inventory.put(isbn, book);
                    return true;
                }
                return false;
            case "remove":
                Book removedBook = inventory.remove(isbn);
                return (removedBook != null);
            default:
                return false;
        }
    }

    public static class Book {
        private String title;
        private String author;

        public Book(String title, String author) {
            this.title = title;
            this.author = author;
        }
    }
}
