from collections import OrderedDict

def task_priority_manager():
    """
    Create a task prioritization system using OrderedDict.
    Only uses move_to_end() and popitem() operations.
    """
    tasks = OrderedDict()

    def add_task(task_id, description):
        """Add a task with default priority (at the end)."""
        tasks[task_id] = description

    def increase_priority(task_id):
        """Move a task to highest priority using move_to_end(last=False)."""
        if task_id in tasks:
            tasks.move_to_end(task_id, last=False)

    def decrease_priority(task_id):
        """Move a task to lowest priority using move_to_end()."""
        if task_id in tasks:
            tasks.move_to_end(task_id)

    def remove_highest_priority():
        """Remove and return the highest priority task using popitem(last=False)."""
        if tasks:
            return tasks.popitem(last=False)
        return None

    def remove_lowest_priority():
        """Remove and return the lowest priority task using popitem()."""
        if tasks:
            return tasks.popitem()
        return None

    return {
        "add": add_task,
        "increase_priority": increase_priority,
        "decrease_priority": decrease_priority,
        "remove_highest": remove_highest_priority,
        "remove_lowest": remove_lowest_priority,
        "all_tasks": tasks
    }
